10→/// Gateway-side implementation of [`SetupBroadcaster`] that delegates to the
11→/// WebSocket broadcast mechanism.
12→pub struct GatewayBroadcaster {
13→    pub state: Arc<GatewayState>,
14→}
15→
16→#[async_trait::async_trait]
17→impl SetupBroadcaster for GatewayBroadcaster {
18→    async fn broadcast(&self, topic: &str, payload: serde_json::Value) {
19→        broadcast(&self.state, topic, payload, BroadcastOpts::default()).await;
20→    }
21→}
