206→function ProviderSection(props) {
207→	var group = props.group;
208→	var [expanded, setExpanded] = useState(false);
209→	var hasMore = group.models.length > DEFAULT_VISIBLE_MODELS;
210→	var visibleModels = expanded || !hasMore ? group.models : group.models.slice(0, DEFAULT_VISIBLE_MODELS);
211→	var hiddenCount = group.models.length - DEFAULT_VISIBLE_MODELS;
212→
213→	function onDeleteProvider() {
214→		if (deletingProvider.value) return;
215→		requestConfirm(t("providers:removeProviderConfirm", { name: group.providerDisplayName })).then((yes) => {
216→			if (!yes) return;
217→			deletingProvider.value = group.provider;
218→			providerActionError.value = "";
219→			sendRpc("providers.remove_key", { provider: group.provider })
220→				.then((res) => {
221→					if (res?.ok) {
222→						configuredModels.value = configuredModels.value.filter((entry) => entry.provider !== group.provider);
223→						fetchModels();
224→						fetchProviders();
225→						return;
226→					}
227→					providerActionError.value = res?.error?.message || t("providers:failedToDeleteProvider");
228→				})
229→				.catch(() => {
230→					providerActionError.value = t("providers:failedToDeleteProvider");
231→				})
232→				.finally(() => {
233→					deletingProvider.value = "";
234→				});
235→		});
236→	}
237→
238→	function onToggleModel(model) {
239→		var method = model.disabled ? "models.enable" : "models.disable";
240→		sendRpc(method, { modelId: model.id }).then((res) => {
241→			if (res?.ok) {
242→				providerActionError.value = "";
243→				configuredModels.value = configuredModels.value.map((entry) =>
244→					entry.id === model.id ? { ...entry, disabled: !model.disabled } : entry,
245→				);
246→				fetchModels();
247→				fetchProviders();
248→			} else {
249→				providerActionError.value = res?.error?.message || t("providers:failedToUpdateModel");
250→			}
251→		});
252→	}
253→
254→	function onSelectModels() {
255→		openModelSelectorForProvider(group.provider, group.providerDisplayName);
256→	}
257→
258→	return html`<div id=${`provider-${group.provider}`} class="max-w-form py-1">
259→		<div class="flex items-center justify-between gap-3">
260→			<div class="flex items-center gap-2 min-w-0">
261→				<h3 class="text-base font-semibold text-[var(--text-strong)] truncate">${group.providerDisplayName}</h3>
262→				<span class="provider-item-badge ${group.authType}">
263→					${group.authType === "oauth" ? t("providers:oauth") : group.authType === "local" ? t("providers:local") : t("providers:apiKey")}
264→				</span>
265→			</div>
266→			<div class="flex gap-2 shrink-0">
267→				${group.models.length > 0 ? html`<button class="provider-btn provider-btn-secondary provider-btn-sm" onClick=${onSelectModels}>${t("providers:preferredModels.button")}</button>` : null}
268→				<button
269→					class="provider-btn provider-btn-danger provider-btn-sm"
270→					disabled=${deletingProvider.value === group.provider}
271→					onClick=${onDeleteProvider}
272→				>
273→					${deletingProvider.value === group.provider ? t("common:status.deleting") : t("common:actions.delete")}
274→				</button>
275→			</div>
276→		</div>
277→		<div class="mt-2 border-b border-[var(--border)]"></div>
278→		${
279→			group.models.length === 0
280→				? html`<div class="mt-2 text-xs text-[var(--muted)]">${t("providers:noActiveModels")}</div>`
281→				: html`<div class="mt-2 flex flex-col gap-2">
282→					${visibleModels.map(
283→						(model) => html`<div key=${model.id} class="flex items-start justify-between gap-3 py-1">
284→							<div class="min-w-0 flex-1">
285→								<div class="flex items-center gap-2 min-w-0">
286→									<div class="text-sm font-medium text-[var(--text-strong)] truncate">${model.displayName || model.id}</div>
287→									${model.preferred ? html`<span class="recommended-badge">${t("providers:preferred")}</span>` : null}
288→									${model.unsupported ? html`<span class="provider-item-badge warning" title=${model.unsupportedReason || t("providers:modelNotSupported")}>${t("providers:unsupported")}</span>` : null}
289→									${model.supportsTools ? null : html`<span class="provider-item-badge warning">${t("providers:chatOnly")}</span>`}
290→									${model.disabled ? html`<span class="provider-item-badge muted">${t("providers:disabled")}</span>` : null}
291→								</div>
292→								<div class="mt-1 text-xs text-[var(--muted)] font-mono opacity-75">${model.id}</div>
293→								${model.unsupported && model.unsupportedReason ? html`<div class="mt-0.5 text-xs font-medium text-[var(--danger,#ef4444)]">${model.unsupportedReason}</div>` : null}
294→								${model.createdAt ? html`<time class="mt-0.5 text-xs text-[var(--muted)] opacity-60 block" data-epoch-ms=${model.createdAt * 1000} data-format="year-month"></time>` : null}
295→							</div>
296→							<button class="provider-btn provider-btn-secondary provider-btn-sm" onClick=${() => onToggleModel(model)}>
297→								${model.disabled ? t("common:actions.enable") : t("common:actions.disable")}
298→							</button>
299→						</div>`,
300→					)}
301→					${
302→						hasMore
303→							? html`<button
304→						class="text-xs text-[var(--accent)] cursor-pointer bg-transparent border-none py-1 text-left hover:underline"
305→						onClick=${() => setExpanded(!expanded)}
306→					>${expanded ? t("providers:showFewerModels") : t("providers:showAllModels", { count: hiddenCount })}</button>`
307→							: null
308→					}
309→				</div>`
310→		}
311→	</div>`;
