 32→/// Callback for publishing events to connected clients.
 33→///
 34→/// The gateway wires this up to its WebSocket broadcast mechanism so the
 35→/// provider-setup crate doesn't depend on the gateway's internal types.
 36→#[async_trait]
 37→pub trait SetupBroadcaster: Send + Sync {
 38→    async fn broadcast(&self, topic: &str, payload: Value);
 39→}
 40→
 41→// ── Key store ──────────────────────────────────────────────────────────────
 42→
 43→/// Per-provider stored configuration (API key, base URL, preferred models).
 44→#[derive(Debug, Clone, Default, serde::Serialize, serde::Deserialize)]
 45→#[serde(rename_all = "camelCase")]
 46→pub struct ProviderConfig {
 47→    #[serde(skip_serializing_if = "Option::is_none")]
 48→    pub api_key: Option<String>,
 49→    #[serde(skip_serializing_if = "Option::is_none")]
 50→    pub base_url: Option<String>,
 51→    #[serde(
 52→        default,
 53→        alias = "model",
 54→        deserialize_with = "deserialize_provider_models",
 55→        skip_serializing_if = "Vec::is_empty"
 56→    )]
 57→    pub models: Vec<String>,
 58→    #[serde(skip_serializing_if = "Option::is_none")]
 59→    pub display_name: Option<String>,
 60→}
 61→
 62→fn deserialize_provider_models<'de, D>(deserializer: D) -> Result<Vec<String>, D::Error>
 63→where
 64→    D: serde::Deserializer<'de>,
 65→{
 66→    let value: Value = serde::Deserialize::deserialize(deserializer)?;
 67→    let normalized = match value {
 68→        Value::Null => Vec::new(),
 69→        Value::String(model) => vec![model],
 70→        Value::Array(values) => values
 71→            .into_iter()
 72→            .filter_map(|value| value.as_str().map(ToString::to_string))
 73→            .collect(),
 74→        _ => {
 75→            return Err(serde::de::Error::custom(
 76→                "models must be a string or string array",
 77→            ));
 78→        },
 79→    };
 80→
 81→    Ok(normalize_model_list(normalized))
 82→}
 83→
 84→fn normalize_model_list(models: impl IntoIterator<Item = String>) -> Vec<String> {
 85→    let mut out = Vec::new();
 86→    for model in models {
 87→        let trimmed = model.trim();
 88→        if trimmed.is_empty() {
 89→            continue;
 90→        }
 91→        // Persist raw IDs so provider-local preferences don't collide with
 92→        // another provider's namespace (e.g. "openai::gpt-5.2").
 93→        let normalized = raw_model_id(trimmed).trim().to_string();
