230→function clampProgressPercent(value) {
231→	if (!Number.isFinite(value)) return 0;
232→	return Math.max(0, Math.min(100, value));
233→}
234→
235→function setValidationProgress(state, value, message) {
236→	if (!state) return;
237→	var next = clampProgressPercent(value);
238→	state.value = Math.max(state.value, next);
239→	state.progress.classList.remove("indeterminate");
240→	state.progressBar.style.width = `${state.value.toFixed(1)}%`;
241→	if (message) {
242→		state.progressText.textContent = message;
243→	}
244→}
245→
246→function resetValidationProgress(state) {
247→	if (!state) return;
248→	state.value = 0;
249→	state.progress.classList.remove("indeterminate");
250→	state.progressBar.style.width = "0%";
251→	state.progressText.textContent = VALIDATION_HINT_TEXT;
252→}
253→
254→function completeValidationProgress(state, text) {
255→	if (!state) return;
256→	setValidationProgress(state, 100, text || "Validation complete.");
257→}
258→
259→function createValidationRequestId() {
260→	var nonce = Math.random().toString(36).slice(2, 10);
261→	return `validate-${Date.now()}-${nonce}`;
262→}
263→
264→function normalizeAttempt(value, fallback) {
265→	if (!Number.isFinite(value)) return fallback;
266→	return Math.max(1, Math.floor(value));
267→}
268→
269→// biome-ignore lint/complexity/noExcessiveCognitiveComplexity: maps backend validation phases to progress UI updates.
270→function progressFromValidationEvent(payload) {
271→	if (!payload?.phase) return null;
272→	var phase = payload.phase;
273→	if (phase === "start") {
274→		return { value: 8, message: payload.message || "Starting provider validation..." };
275→	}
276→	if (phase === "candidates_discovered") {
277→		var count = Number.isFinite(payload.modelCount) ? payload.modelCount : null;
278→		var message = count == null ? "Discovered candidate models." : `Discovered ${count} candidate models.`;
279→		return { value: 24, message };
280→	}
281→	if (phase === "probe_started" || phase === "probe_failed" || phase === "probe_timeout") {
282→		var total = normalizeAttempt(payload.totalAttempts, 1);
283→		var attempt = Math.min(normalizeAttempt(payload.attempt, 1), total);
284→		var value = 24 + (attempt / total) * 62;
285→		var modelName = stripModelNamespace(payload.modelId);
286→		var defaultMessage = modelName
287→			? `Probing ${modelName} (${attempt}/${total})...`
288→			: `Probing model ${attempt}/${total}...`;
289→		return {
290→			value,
291→			message: payload.message || defaultMessage,
292→		};
293→	}
294→	if (phase === "probe_succeeded") {
295→		return { value: 94, message: payload.message || "Model probe succeeded." };
296→	}
297→	if (phase === "complete") {
298→		return { value: 100, message: payload.message || "Validation complete." };
299→	}
300→	if (phase === "error") {
301→		return { value: 98, message: payload.message || "Validation failed." };
302→	}
303→	return null;
304→}
305→
306→function bindValidationProgressEvents(state, requestId) {
307→	if (!(state && requestId)) return () => undefined;
308→	var off = onEvent(VALIDATION_PROGRESS_EVENT, (payload) => {
309→		if (!payload || payload.requestId !== requestId) return;
310→		var update = progressFromValidationEvent(payload);
311→		if (!update) return;
312→		setValidationProgress(state, update.value, update.message);
313→	});
314→	return () => {
315→		off();
316→	};
317→}
