596→
597→		saveBtn.disabled = true;
598→		saveBtn.textContent = "Validating...";
599→		setValidationProgress(validationProgress, 10, VALIDATION_HINT_RUNNING_TEXT);
600→		setFormError(errorPanel, null);
601→
602→		var keyVal = key || provider.name;
603→		var endpointVal = endpointInp?.value.trim() || null;
604→		var modelVal = modelInp?.value.trim() || null;
605→		var requestId = createValidationRequestId();
606→		var stopProgressEvents = bindValidationProgressEvents(validationProgress, requestId);
607→
608→		validateProviderKey(provider.name, keyVal, endpointVal, modelVal, requestId)
609→			.then((result) => {
610→				if (!result.valid) {
611→					saveBtn.disabled = false;
612→					saveBtn.textContent = "Save & Validate";
613→					resetValidationProgress(validationProgress);
614→					setFormError(errorPanel, result.error || "Validation failed. Please check your credentials.");
615→					return;
616→				}
617→
618→				// BYOM providers already tested the specific model — save directly.
619→				if (needsModel) {
620→					completeValidationProgress(validationProgress, "Validation complete.");
621→					saveAndFinishProvider(provider, keyVal, endpointVal, modelVal, null, false);
622→					return;
623→				}
624→
625→				// Regular providers — show model selector.
626→				var models = result.models || [];
627→				completeValidationProgress(validationProgress, "Validation complete.");
628→				showModelSelector(provider, models, keyVal, endpointVal, modelVal);
629→			})
630→			.catch((err) => {
631→				saveBtn.disabled = false;
632→				saveBtn.textContent = "Save & Validate";
633→				resetValidationProgress(validationProgress);
634→				setFormError(errorPanel, err?.message || "Validation failed.");
635→			})
636→			.finally(() => {
637→				stopProgressEvents();
638→			});
639→	});
640→	btns.appendChild(saveBtn);
641→	form.appendChild(btns);
642→	m.body.appendChild(form);
643→	keyInp.focus();
644→}
