782→function saveAndFinishProvider(provider, keyVal, endpointVal, modelVal, selectedModelId, skipSave) {
783→	var m = els();
784→	var saveAsCustomProvider = !skipSave && shouldUseCustomProviderForOpenAi(provider, endpointVal);
785→	var selectedModelForSave = selectedModelId;
786→	if (saveAsCustomProvider && selectedModelForSave) {
787→		selectedModelForSave = stripModelNamespace(selectedModelForSave);
788→	}
789→	var effectiveModelVal = provider.keyOptional && selectedModelForSave ? selectedModelForSave : modelVal;
790→
791→	function showError(msg) {
792→		var wrapper = m.body.querySelector(".provider-key-form");
793→		if (wrapper?._errorArea) {
794→			setFormError(wrapper._errorArea, msg);
795→			if (wrapper._resetSelection) wrapper._resetSelection();
796→		}
797→	}
798→
799→	var savePromise;

 800→	if (skipSave) {
 801→		savePromise = Promise.resolve({ ok: true });
 802→	} else if (saveAsCustomProvider) {
 803→		var customPayload = { baseUrl: endpointVal, apiKey: keyVal };
 804→		var customModel = selectedModelForSave || stripModelNamespace(effectiveModelVal);
 805→		if (customModel) customPayload.model = customModel;
 806→		savePromise = sendRpc("providers.add_custom", customPayload);
 807→	} else {
 808→		savePromise = saveProviderKey(provider.name, keyVal, endpointVal, effectiveModelVal);
 809→	}
 810→
 811→	savePromise
 812→		.then(async (res) => {
 813→			if (!res?.ok) {
 814→				showError(res?.error?.message || "Failed to save credentials.");
 815→				return;
 816→			}
 817→			var savedProviderName = saveAsCustomProvider ? res?.payload?.providerName || provider.name : provider.name;
 818→			var successDisplayName = saveAsCustomProvider
 819→				? res?.payload?.displayName || provider.displayName
 820→				: provider.displayName;
 821→
 822→			if (selectedModelId) {
 823→				var modelForStorage = selectedModelForSave || selectedModelId;
 824→				var modelForTest = saveAsCustomProvider ? `${savedProviderName}::${modelForStorage}` : selectedModelId;
 825→				var testResult = await testModel(modelForTest);
 826→				var modelServiceUnavailable = !testResult.ok && isModelServiceNotConfigured(testResult.error || "");
 827→				var modelTimedOut = !testResult.ok && isTimeoutError(testResult.error || "");
 828→				if (!(testResult.ok || modelServiceUnavailable || modelTimedOut)) {
 829→					showError(testResult.error || "Model test failed. Try another model.");
 830→					return;
 831→				}
 832→				if (modelTimedOut) {
 833→					console.warn(
 834→						"models.test timed out for",
 835→						modelForTest,
 836→						"— saving model anyway (local servers may need longer to load)",
 837→					);
 838→				}
 839→				await sendRpc("providers.save_model", { provider: savedProviderName, model: modelForStorage });
 840→				if (modelServiceUnavailable) {
 841→					console.warn("models.test unavailable in provider settings, saved selected model without probe");
 842→				}
 843→				localStorage.setItem("moltis-model", modelForTest);
 844→			}
 845→
 846→			// Success
 847→			m.body.textContent = "";
 848→			var status = document.createElement("div");
 849→			status.className = "provider-status";
 850→			status.textContent = `${successDisplayName} configured successfully!`;
 851→			m.body.appendChild(status);
 852→			if (modelTimedOut) {
 853→				var slowHint = document.createElement("div");
 854→				slowHint.className = "text-xs text-[var(--muted)] mt-1";
 855→				slowHint.textContent = "Note: model was slow to respond. It may need a moment to finish loading.";
 856→				m.body.appendChild(slowHint);
 857→			}
 858→			fetchModels();
 859→			if (S.refreshProvidersPage) S.refreshProvidersPage();
 860→			setTimeout(closeProviderModal, modelTimedOut ? 3500 : 1500);
 861→		})
 862→		.catch((err) => {
 863→			showError(err?.message || "Failed to save credentials.");
 864→		});
 865→}
