1008→function pollOAuthStatus(provider, onAuthenticated) {
1009→	var m = els();
1010→	var attempts = 0;
1011→	var maxAttempts = 60;
1012→	clearOAuthStatusTimer();
1013→	oauthStatusTimer = setInterval(() => {
1014→		attempts++;
1015→		if (attempts > maxAttempts) {
1016→			clearOAuthStatusTimer();
1017→			m.body.textContent = "";
1018→			var timeout = document.createElement("div");
1019→			timeout.className = "text-xs text-[var(--error)]";
1020→			timeout.textContent = "OAuth timed out. Please try again.";
1021→			m.body.appendChild(timeout);
1022→			return;
1023→		}
1024→		sendRpc("providers.oauth.status", { provider: provider.name }).then((res) => {
1025→			if (res?.ok && res.payload && res.payload.authenticated) {
1026→				clearOAuthStatusTimer();
1027→				if (typeof onAuthenticated === "function") {
1028→					onAuthenticated();
1029→					return;
1030→				}
1031→				showOAuthModelSelector(provider);
1032→			}
1033→		});
1034→	}, 2000);
1035→}
