1042→
1043→		if (provModels.length > 0) {
1044→			var mapped = provModels.map((entry) => ({
1045→				id: entry.id,
1046→				displayName: entry.displayName || entry.id,
1047→				provider: entry.provider,
1048→				supportsTools: entry.supportsTools,
1049→			}));

1050→			showModelSelector(provider, mapped, null, null, null, true);
1051→		} else {
