1079→	Promise.all([sendRpc("models.list", {}), sendRpc("providers.available", {})]).then(([modelsRes, providersRes]) => {
1080→		var allModels = modelsRes?.ok ? modelsRes.payload || [] : [];
1081→		var needle = providerName.replace(/-/g, "").toLowerCase();
1082→		var provModels = allModels.filter((entry) => entry.provider?.toLowerCase().replace(/-/g, "").includes(needle));
1083→
1084→		if (provModels.length === 0) {
1085→			m.body.textContent = "";
1086→			var wrapper = document.createElement("div");
1087→			wrapper.className = "provider-key-form";
1088→			var msg = document.createElement("div");
1089→			msg.className = "text-xs text-[var(--muted)] py-4 text-center";
