1100→			m.body.appendChild(wrapper);
1101→			return;
1102→		}
1103→
1104→		// Get saved preferred models for this provider.
1105→		var savedModels = new Set();
1106→		if (providersRes?.ok) {
1107→			var providerMeta = (providersRes.payload || []).find((p) => p.name === providerName);
1108→			if (providerMeta?.models) {
