1113→		var mapped = provModels.map((entry) => ({
1114→			id: entry.id,
1115→			displayName: entry.displayName || entry.id,
1116→			provider: entry.provider,
1117→			supportsTools: entry.supportsTools,
1118→			createdAt: entry.createdAt || 0,
1119→		}));
1120→		showMultiModelSelector(providerName, providerDisplayName, mapped, savedModels);
1121→	});
