1123→
1124→function showMultiModelSelector(providerName, providerDisplayName, models, savedModels) {
1125→	var m = els();
1126→	m.title.textContent = `${providerDisplayName} — Preferred Models`;
1127→	m.body.textContent = "";
1128→
1129→	var selectedIds = new Set(savedModels);
1130→
1131→	// Track per-model probe state: "probing" | "ok" | { error: string }
1132→	var probeResults = new Map();
1133→
1134→	function probeModel(modelId) {
1135→		if (probeResults.has(modelId)) return;
1136→		probeResults.set(modelId, "probing");
1137→		renderCards(searchInp?.value.trim() || null);
1138→		testModel(modelId).then((result) => {
1139→			if (isModelServiceNotConfigured(result.error || "")) {
1140→				// Model service not ready — don't flag as broken.
1141→				probeResults.delete(modelId);
1142→			} else if (!result.ok && isTimeoutError(result.error || "")) {
1143→				// Timeout — model may still work, local servers need time to load.
1144→				probeResults.set(modelId, { error: "Slow to respond (may still work)", timeout: true });
1145→			} else {
