1689→                let configured = self.is_provider_configured(provider, &active_config);
1690→                let normalized_name = normalize_provider_name(provider.name);
1691→                if let Some(allowed) = offered.as_ref()
1692→                    && !allowed.contains(&normalized_name)
1693→                    && !configured
1694→                {
1695→                    return None;
1696→                }
1697→
1698→                // Get saved config for this provider (baseUrl, preferred models)
1699→                let saved_config = self.key_store.load_config(provider.name);
