1712→                        "authType": provider.auth_type.as_str(),
1713→                        "configured": configured,
1714→                        "defaultBaseUrl": provider.default_base_url,
1715→                        "baseUrl": base_url,
1716→                        "models": models,
1717→                        "model": model,
1718→                        "requiresModel": provider.requires_model,
1719→                        "keyOptional": provider.key_optional,
1720→                    }),
1721→                ))
1722→            })
1723→            .collect();
1724→
1725→        // Append custom providers from the key store.
1726→        let known_count = providers.len();
1727→        for (name, config) in self.key_store.load_all_configs() {
1728→            if !is_custom_provider(&name) {
1729→                continue;
1730→            }
1731→            if active_config.get(&name).is_some_and(|entry| !entry.enabled) {
1732→                continue;
1733→            }
1734→            let display_name = config.display_name.clone().unwrap_or_else(|| name.clone());
1735→            let base_url = config.base_url.clone();
1736→            let models = normalize_model_list(config.models.clone());
1737→            let model = models.first().cloned();
1738→
1739→            providers.push((
1740→                None,
1741→                known_count, // sort after all known providers
1742→                serde_json::json!({
1743→                    "name": name,
1744→                    "displayName": display_name,
1745→                    "authType": "api-key",
1746→                    "configured": true,
1747→                    "defaultBaseUrl": base_url,
1748→                    "baseUrl": base_url,
1749→                    "models": models,
1750→                    "model": model,
1751→                    "requiresModel": true,
1752→                    "keyOptional": false,
1753→                    "isCustom": true,
1754→                }),
1755→            ));
1756→        }
1757→
1758→        providers.sort_by(
1759→            |(a_offered, a_known, a_value), (b_offered, b_known, b_value)| {
1760→                let offered_cmp = match (a_offered, b_offered) {
1761→                    (Some(a), Some(b)) => a.cmp(b),
1762→                    (Some(_), None) => std::cmp::Ordering::Less,
1763→                    (None, Some(_)) => std::cmp::Ordering::Greater,
1764→                    (None, None) => std::cmp::Ordering::Equal,
1765→                };
1766→                if offered_cmp != std::cmp::Ordering::Equal {
1767→                    return offered_cmp;
1768→                }
1769→
1770→                let known_cmp = a_known.cmp(b_known);
1771→                if known_cmp != std::cmp::Ordering::Equal {
1772→                    return known_cmp;
1773→                }
1774→
1775→                let a_name = a_value
1776→                    .get("displayName")
1777→                    .and_then(|v| v.as_str())
1778→                    .unwrap_or_default();
1779→                let b_name = b_value
1780→                    .get("displayName")
1781→                    .and_then(|v| v.as_str())
1782→                    .unwrap_or_default();
1783→                a_name.cmp(b_name)
1784→            },
1785→        );
1786→
1787→        let providers: Vec<Value> = providers
1788→            .into_iter()
1789→            .enumerate()
1790→            .map(|(idx, (_, _, mut value))| {
1791→                if let Some(obj) = value.as_object_mut() {
1792→                    obj.insert("uiOrder".into(), serde_json::json!(idx));
1793→                }
1794→                value
1795→            })
1796→            .collect();
1797→
1798→        Ok(Value::Array(providers))
1799→    }
