206→    /// Load all provider configs. Handles migration from old format (string values).
207→    fn load_all_configs_from_path(path: &PathBuf) -> HashMap<String, ProviderConfig> {
208→        let content = match std::fs::read_to_string(path) {
209→            Ok(c) => c,
210→            Err(error) => {
211→                if error.kind() != std::io::ErrorKind::NotFound {
212→                    warn!(
213→                        path = %path.display(),
214→                        error = %error,
215→                        "failed to read provider key store"
216→                    );
217→                }
218→                return HashMap::new();
219→            },
220→        };
221→
222→        // Try parsing as new format first
223→        if let Ok(configs) = serde_json::from_str::<HashMap<String, ProviderConfig>>(&content) {
224→            return configs;
225→        }
226→
227→        // Fall back to old format migration: { "provider": "api-key-string" }
228→        if let Ok(old_format) = serde_json::from_str::<HashMap<String, String>>(&content) {
229→            return old_format
230→                .into_iter()
231→                .map(|(k, v)| {
232→                    (k, ProviderConfig {
233→                        api_key: Some(v),
234→                        base_url: None,
235→                        models: Vec::new(),
236→                        display_name: None,
237→                    })
238→                })
239→                .collect();
240→        }
241→
242→        warn!(
243→            path = %path.display(),
244→            "provider key store is invalid JSON and will be ignored"
245→        );
246→        HashMap::new()
247→    }
