254→    /// Save all provider configs to disk.
255→    fn save_all_configs_to_path(
256→        path: &PathBuf,
257→        configs: &HashMap<String, ProviderConfig>,
258→    ) -> error::Result<()> {
259→        if let Some(parent) = path.parent() {
260→            std::fs::create_dir_all(parent).map_err(|error| {
261→                warn!(
262→                    path = %parent.display(),
263→                    error = %error,
264→                    "failed to create provider key store directory"
265→                );
266→                error::Error::external("failed to create provider key store directory", error)
267→            })?;
268→        }
269→        let data = serde_json::to_string_pretty(configs).map_err(|error| {
270→            warn!(error = %error, "failed to serialize provider key store");
271→            error
272→        })?;
273→
274→        // Write atomically via temp file + rename so readers never observe
275→        // partially-written JSON.
276→        let nanos = std::time::SystemTime::now()
277→            .duration_since(std::time::UNIX_EPOCH)
278→            .map(|d| d.as_nanos())
279→            .unwrap_or(0);
280→        let temp_path = path.with_extension(format!("json.tmp.{nanos}"));
281→        std::fs::write(&temp_path, &data).map_err(|error| {
282→            warn!(
283→                path = %temp_path.display(),
284→                error = %error,
285→                "failed to write provider key store temp file"
286→            );
287→            error::Error::external("failed to write provider key store temp file", error)
288→        })?;
289→        #[cfg(unix)]
290→        {
291→            use std::os::unix::fs::PermissionsExt;
292→            let _ = std::fs::set_permissions(&temp_path, std::fs::Permissions::from_mode(0o600));
293→        }
294→
295→        std::fs::rename(&temp_path, path).map_err(|error| {
296→            warn!(
297→                temp_path = %temp_path.display(),
298→                path = %path.display(),
299→                error = %error,
300→                "failed to atomically replace provider key store"
301→            );
302→            error::Error::external("failed to atomically replace provider key store", error)
303→        })?;
304→
305→        Ok(())
306→    }
