364→        base_url: Option<String>,
365→        models: Option<Vec<String>>,
366→        display_name: Option<String>,
367→    ) -> error::Result<()> {
368→        let guard = self.lock();
369→        let mut configs = Self::load_all_configs_from_path(&guard.path);
370→        let entry = configs.entry(provider.to_string()).or_default();
371→
372→        // Only update fields that are provided (Some), preserve existing for None
373→        if let Some(key) = api_key {
374→            entry.api_key = Some(key);
375→        }
376→        if let Some(url) = base_url {
