1076→	m.title.textContent = `${providerDisplayName} — Preferred Models`;
1077→	m.body.textContent = "Loading models...";
1078→
1079→	Promise.all([sendRpc("models.list", {}), sendRpc("providers.available", {})]).then(([modelsRes, providersRes]) => {
1080→		var allModels = modelsRes?.ok ? modelsRes.payload || [] : [];
1081→		var needle = providerName.replace(/-/g, "").toLowerCase();
1082→		var provModels = allModels.filter((entry) => entry.provider?.toLowerCase().replace(/-/g, "").includes(needle));
1083→
1084→		if (provModels.length === 0) {
1085→			m.body.textContent = "";
1086→			var wrapper = document.createElement("div");
1087→			wrapper.className = "provider-key-form";
1088→			var msg = document.createElement("div");
1089→			msg.className = "text-xs text-[var(--muted)] py-4 text-center";
1090→			msg.textContent = "No models available yet. Try running Detect All Models first.";
1091→			wrapper.appendChild(msg);
1092→			var btns = document.createElement("div");
1093→			btns.className = "btn-row mt-3";
1094→			var closeBtn = document.createElement("button");
1095→			closeBtn.className = "provider-btn provider-btn-secondary";
1096→			closeBtn.textContent = "Close";
1097→			closeBtn.addEventListener("click", closeProviderModal);
1098→			btns.appendChild(closeBtn);
1099→			wrapper.appendChild(btns);
1100→			m.body.appendChild(wrapper);
1101→			return;
1102→		}
1103→
1104→		// Get saved preferred models for this provider.
1105→		var savedModels = new Set();
1106→		if (providersRes?.ok) {
1107→			var providerMeta = (providersRes.payload || []).find((p) => p.name === providerName);
1108→			if (providerMeta?.models) {
1109→				for (var sm of providerMeta.models) savedModels.add(sm);
1110→			}
1111→		}
1112→
1113→		var mapped = provModels.map((entry) => ({
1114→			id: entry.id,
1115→			displayName: entry.displayName || entry.id,
1116→			provider: entry.provider,
1117→			supportsTools: entry.supportsTools,
1118→			createdAt: entry.createdAt || 0,
1119→		}));
1120→		showMultiModelSelector(providerName, providerDisplayName, mapped, savedModels);
1121→	});
